import { Navigate } from "react-router-dom";

function ProtectedRoute({ children }) {
  const isLoggedIn = localStorage.getItem("isLoggedIn");
  console.log("Login status:", isLoggedIn);

  if (isLoggedIn !== "true") {
    return <Navigate to="/" />; 
  }

  return children;
}

export default ProtectedRoute;
